function createRenderer() {
  const noise2D = simplex && simplex.createNoise2D
    ? simplex.createNoise2D(() => 0.618)
    : (x, y) => Math.sin(x * 1.7 + y * 2.3) * 0.5 + Math.sin(x * 0.4 - y * 0.9) * 0.3;

  const stars = Array.from({ length: 200 }, (_, i) => ({
    x: (i * 137.508) % 1,
    y: (i * 73.137) % 1,
    r: 0.5 + (i % 5) * 0.4,
    tw: 0.5 + Math.random(),
    ph: Math.random() * Math.PI * 2,
  }));

  function clamp(v) { return Math.max(0, Math.min(1, v)); }
  function easeOut(v) { v = clamp(v); return 1 - Math.pow(1 - v, 3); }

  function render(t, context) {
    const ctx = context.mainContext;
    const w = context.width;
    const h = context.height;

    // Deep night sky
    const sky = ctx.createLinearGradient(0, 0, 0, h);
    sky.addColorStop(0, '#0a0e27');
    sky.addColorStop(0.4, '#0d1b3e');
    sky.addColorStop(1, '#1a0a2e');
    ctx.fillStyle = sky;
    ctx.fillRect(0, 0, w, h);

    // Stars
    for (const s of stars) {
      const tw = 0.3 + 0.7 * Math.abs(Math.sin(t * s.tw + s.ph));
      ctx.globalAlpha = tw * 0.8;
      ctx.fillStyle = '#fff';
      ctx.beginPath();
      ctx.arc(s.x * w, s.y * h * 0.6, s.r, 0, Math.PI * 2);
      ctx.fill();
    }
    ctx.globalAlpha = 1;

    // Aurora curtains — layered simplex noise ribbons
    const layers = [
      { hue: [0, 255, 180], yBase: 0.25, speed: 0.12, amp: 0.18, alpha: 0.55 },
      { hue: [120, 80, 255], yBase: 0.35, speed: 0.09, amp: 0.22, alpha: 0.45 },
      { hue: [255, 60, 200], yBase: 0.45, speed: 0.15, amp: 0.15, alpha: 0.35 },
    ];

    for (const L of layers) {
      ctx.save();
      ctx.globalCompositeOperation = 'screen';
      ctx.globalAlpha = L.alpha * easeOut(t / 1.5);

      for (let band = 0; band < 5; band++) {
        ctx.beginPath();
        const bandY = h * (L.yBase + band * 0.04);
        for (let x = 0; x <= w; x += 3) {
          const nx = x * 0.002 + t * L.speed;
          const ny = band * 0.5 + t * L.speed * 0.3;
          const n1 = noise2D(nx, ny);
          const n2 = noise2D(nx * 2.1 + 50, ny * 1.7);
          const y = bandY + (n1 * 0.6 + n2 * 0.4) * h * L.amp;
          x === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
        }
        ctx.lineTo(w, h);
        ctx.lineTo(0, h);
        ctx.closePath();

        const grad = ctx.createLinearGradient(0, bandY - h * 0.1, 0, bandY + h * 0.3);
        grad.addColorStop(0, `rgba(${L.hue[0]},${L.hue[1]},${L.hue[2]},0.7)`);
        grad.addColorStop(0.5, `rgba(${L.hue[0]},${L.hue[1]},${L.hue[2]},0.2)`);
        grad.addColorStop(1, 'rgba(0,0,0,0)');
        ctx.fillStyle = grad;
        ctx.fill();
      }
      ctx.restore();
    }

    // Ground silhouette — mountain range
    ctx.save();
    ctx.globalAlpha = easeOut((t - 1) / 1.2);
    ctx.fillStyle = '#050a18';
    ctx.beginPath();
    ctx.moveTo(0, h);
    for (let x = 0; x <= w; x += 4) {
      const mx = noise2D(x * 0.003, 10) * h * 0.12 + noise2D(x * 0.008, 20) * h * 0.06;
      ctx.lineTo(x, h * 0.72 + mx);
    }
    ctx.lineTo(w, h);
    ctx.closePath();
    ctx.fill();
    ctx.restore();

    // Title
    const titleA = easeOut(clamp((t - 2.5) / 1));
    ctx.save();
    ctx.globalAlpha = titleA;
    ctx.textAlign = 'center';
    ctx.font = '300 56px Georgia, serif';
    ctx.fillStyle = 'rgba(255,255,255,0.9)';
    ctx.fillText('Aurora Fluid', w / 2, h * 0.88);
    ctx.font = '400 20px Arial, sans-serif';
    ctx.fillStyle = 'rgba(180,220,255,0.6)';
    ctx.fillText('simplex noise · layered curtains · organic flow', w / 2, h * 0.93);
    ctx.restore();
  }

  return { render };
}
